// ============================================================
// washes-timeline.standalone.js — classic <script>-tag build of the
// timeline sidecar. Generated by scripts/build-standalone.cjs from
// src/washes-timeline.js (export keywords stripped). Attaches
// window.WashesTimeline / window.washesEasings.
// ============================================================
/**
 * washes-timeline.js — declarative stroke choreography for Washes.
 * v1.0.0 (sidecar; pairs with washes engine ≥ 1.7.0)
 *
 * A tiny, dependency-free driver that animates the engine's existing pen
 * (strokeToNorm / penUp) along eased paths over time, sequenced on the
 * engine's own frame clock (onFrame) rather than setTimeout — so it pauses
 * with the sim, survives the performance governor's rescales (the engine
 * rescales in-flight stroke state since 1.7.0), and respects reduced motion.
 *
 * Why a sidecar: this touches no simulation code. It only schedules public
 * calls, so it ships separately and keeps the core engine smaller.
 *
 * Usage:
 *   import { WashesTimeline, easings } from './washes-timeline.js';
 *   // or: <script src="washes-timeline.js"></script>  → window.WashesTimeline
 *
 *   const tl = new WashesTimeline(wc);          // wc = a Washes instance
 *   tl.stroke([[0.2,0.5],[0.8,0.5]], { duration: 900, easing: 'easeInOut',
 *                                      pigment: 'blue', nradius: 0.03, strength: 0.6 })
 *     .wait(150)
 *     .stroke(handlePts, { duration: 600, easing: 'easeOut', pigment: 'rose' })
 *     .play()
 *     .then(() => console.log('done'));
 *
 *   tl.pause(); tl.resume(); tl.cancel();
 *
 * A single one-off stroke:
 *   tl.once([[0.1,0.1],[0.9,0.9]], { duration: 800 });   // builds + plays, returns Promise
 */

const easings = {
  linear: (t) => t,
  easeIn: (t) => t * t,
  easeOut: (t) => 1 - (1 - t) * (1 - t),
  easeInOut: (t) => (t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2),
  easeOutBack: (t) => { const c1 = 1.70158, c3 = c1 + 1; return 1 + c3 * Math.pow(t - 1, 3) + c1 * Math.pow(t - 1, 2); },
  easeOutCubic: (t) => 1 - Math.pow(1 - t, 3),
};

function resolveEasing(e) {
  if (typeof e === "function") return e;
  if (typeof e === "string" && easings[e]) return easings[e];
  return easings.easeInOut;
}

// Total polyline length and a position sampler in normalized space.
function makePathSampler(points) {
  const segLen = [];
  let total = 0;
  for (let i = 1; i < points.length; i++) {
    const dx = points[i][0] - points[i - 1][0];
    const dy = points[i][1] - points[i - 1][1];
    const l = Math.hypot(dx, dy);
    segLen.push(l); total += l;
  }
  // at(u): u in 0..1 → [x,y] along the polyline by arc length
  return {
    total,
    at(u) {
      if (points.length === 1 || total === 0) return points[0].slice();
      if (u <= 0) return points[0].slice();
      if (u >= 1) return points[points.length - 1].slice();
      let d = u * total, i = 0;
      while (i < segLen.length && d > segLen[i]) { d -= segLen[i]; i++; }
      const t = segLen[i] ? d / segLen[i] : 0;
      const a = points[i], b = points[i + 1];
      return [a[0] + (b[0] - a[0]) * t, a[1] + (b[1] - a[1]) * t];
    },
  };
}

class WashesTimeline {
  constructor(wc, opts) {
    // v2.0.0 — the engine renamed strokeToNorm to stroke; accept both so
    // the sidecar drives v2 instances, compat1 wrappers, and old engines.
    const strokeFn = wc && (typeof wc.stroke === "function" ? wc.stroke
      : typeof wc.strokeToNorm === "function" ? wc.strokeToNorm : null);
    if (!strokeFn)
      throw new Error("WashesTimeline(wc): expected a Washes instance with stroke()/strokeToNorm()");
    this.wc = wc;
    this._stroke = (nx, ny, opts) => strokeFn.call(wc, nx, ny, opts);
    this._steps = [];
    this._reduced = !!(opts && opts.reducedMotion) ||
      (typeof matchMedia === "function" && matchMedia("(prefers-reduced-motion: reduce)").matches);
    this._state = "idle";        // idle | playing | paused | done | cancelled
    this._unsub = null;
    this._resolve = null;
    this._reject = null;
  }

  // Queue a stroke along `points` (array of [nx,ny] in 0..1) over `duration` ms.
  stroke(points, opts) {
    if (!Array.isArray(points) || points.length < 1)
      throw new Error("stroke(points): expected a non-empty array of [nx,ny] points");
    opts = opts || {};
    this._steps.push({
      type: "stroke",
      points: points.map((p) => [p[0], p[1]]),
      duration: opts.duration == null ? 800 : Math.max(0, +opts.duration),
      easing: resolveEasing(opts.easing),
      strokeOpts: {
        pigment: opts.pigment,
        nradius: opts.nradius == null ? 0.03 : +opts.nradius,  // v2.0.0 — aligned with the engine default
        strength: opts.strength == null ? 0.6 : +opts.strength,
        spacing: opts.spacing,
      },
    });
    return this;
  }

  // Queue a pause.
  wait(ms) {
    this._steps.push({ type: "wait", duration: Math.max(0, +ms || 0) });
    return this;
  }

  // Queue an arbitrary callback (fires once when reached).
  call(fn) {
    if (typeof fn === "function") this._steps.push({ type: "call", fn });
    return this;
  }

  // Build + play a single stroke in one call.
  once(points, opts) {
    return this.stroke(points, opts).play();
  }

  play() {
    if (this._state === "playing") return this._promise;
    this._state = "playing";
    this._promise = new Promise((res, rej) => { this._resolve = res; this._reject = rej; });

    let si = 0;                 // step index
    let stepStart = null;       // engine-clock ms at step start
    let penActive = false;
    const wc = this.wc;

    const finishStroke = () => { if (penActive) { try { wc.penUp(); } catch (_) {} penActive = false; } };

    const tick = (info) => {
      // info.now is engine time in ms (onFrame provides a timestamp); fall back
      // to performance.now if the engine passes something else.
      const now = (info && typeof info.now === "number") ? info.now
                : (info && typeof info.t === "number") ? info.t
                : (typeof performance !== "undefined" ? performance.now() : Date.now());
      if (this._state !== "playing") return;

      while (si < this._steps.length) {
        const step = this._steps[si];
        if (stepStart === null) stepStart = now;
        const elapsed = now - stepStart;

        if (step.type === "wait") {
          if (this._reduced || elapsed >= step.duration) { si++; stepStart = null; continue; }
          return;
        }
        if (step.type === "call") { try { step.fn(); } catch (_) {} si++; stepStart = null; continue; }

        // stroke
        const sampler = step._sampler || (step._sampler = makePathSampler(step.points));
        if (this._reduced || step.duration === 0) {
          // paint the whole path immediately
          for (let k = 0; k < step.points.length; k++) {
            const p = step.points[k];
            try { this._stroke(p[0], p[1], step.strokeOpts); } catch (_) {}
          }
          finishStroke(); si++; stepStart = null; continue;
        }
        const u = Math.min(1, elapsed / step.duration);
        const e = step.easing(u);
        const pos = sampler.at(e);
        try { this._stroke(pos[0], pos[1], step.strokeOpts); penActive = true; } catch (_) {}
        if (u >= 1) { finishStroke(); si++; stepStart = null; continue; }
        return;   // mid-stroke, wait for next frame
      }

      // all steps consumed
      this._cleanup("done");
    };

    // Subscribe to the engine frame clock. onFrame returns an unsubscribe.
    try { this._unsub = wc.onFrame(tick); }
    catch (e) { this._cleanup("error", e); }

    // Nudge the sim awake so frames flow even on an idle canvas.
    try { this._stroke(this._steps[0] && this._steps[0].points ? this._steps[0].points[0][0] : 0.5,
                       this._steps[0] && this._steps[0].points ? this._steps[0].points[0][1] : 0.5,
                       { pigment: "water", strength: 0 }); wc.penUp(); } catch (_) {}

    return this._promise;
  }

  pause() { if (this._state === "playing") this._state = "paused"; return this; }
  resume() { if (this._state === "paused") this._state = "playing"; return this; }
  cancel() { this._cleanup("cancelled"); return this; }

  _cleanup(state, err) {
    if (this._unsub) { try { this._unsub(); } catch (_) {} this._unsub = null; }
    try { this.wc.penUp(); } catch (_) {}
    this._state = state;
    if (state === "done") { this._resolve && this._resolve(); }
    else if (state === "error") { this._reject && this._reject(err); }
    else if (state === "cancelled") { this._resolve && this._resolve({ cancelled: true }); }
  }

  get state() { return this._state; }
}

// UMD-ish global for <script> users.
if (typeof window !== "undefined") {
  window.WashesTimeline = WashesTimeline;
  window.washesEasings = easings;
}
